+     * @return caption as string
+     */
+    private fun prettyCaption(media: Media): String {
+        for (caption: String in media.captions.values) {
+            return if (caption == "") {
+                getString(R.string.detail_caption_empty)
+            } else {
+                caption
+            }
+        }
+        return getString(R.string.detail_caption_empty)
